  1987→func (a *Server) validateMFAAuthResponse(ctx context.Context, user string, resp *proto.MFAAuthenticateResponse, u2fStorage u2f.AuthenticationStorage) error {
  1988→	switch res := resp.Response.(type) {
  1989→	case *proto.MFAAuthenticateResponse_TOTP:
  1990→		return a.checkOTP(user, res.TOTP.Code)
  1991→	case *proto.MFAAuthenticateResponse_U2F:
  1992→		return a.checkU2F(ctx, user, u2f.AuthenticateChallengeResponse{
  1993→			KeyHandle:     res.U2F.KeyHandle,
  1994→			ClientData:    res.U2F.ClientData,
  1995→			SignatureData: res.U2F.Signature,
  1996→		}, u2fStorage)
  1997→	default:
  1998→		return trace.BadParameter("unknown or missing MFAAuthenticateResponse type %T", resp.Response)
  1999→	}

