	// TEST 1: Verify OLD API (U2FSignRequest) - should expose the bug
	t.Run("OldAPI_SingleDeviceChallenge_BUG", func(t *testing.T) {
		// The old U2FSignRequest API returns only ONE challenge (for the first device found)
		// This is the bug - it should return challenges for ALL devices
		//
		// We can't directly call U2FSignRequest from here, but we can verify through the
		// auth server that it has this limitation.
		// The bug is in: lib/auth/auth.go U2FSignRequest() func at line 828-864
		//
		// The function has this code:
		//   for _, dev := range devs {
		//       if dev.GetU2F() == nil { continue }
		//       return u2f.AuthenticateInit(...) // BUG: returns immediately on first device
		//   }
		//
		// This means only the first device gets a challenge, users can't choose which device to use.

		// Verify that U2FSignRequest only handles the first device
		// by checking the behavior through the auth server
		devList, err := as.AuthServer.GetMFADevices(ctx, user.GetName())
		require.NoError(t, err)
		require.Len(t, devList, 3)

		// The old API would only return a challenge for the first U2F device
		// To properly test this, we'd need to call U2FSignRequest, but it requires
		// a valid password which we don't have in this test context.
		// However, the bug is confirmed by examining the code:
		// - U2FSignRequest has a TODO comment at line 847 saying "support challenge with multiple devices"
		// - The loop returns immediately on the first device instead of collecting all devices
	})

	// TEST 2: Verify NEW API (mfaAuthChallenge) - should work correctly
	t.Run("NewAPI_MultiDeviceChallenge_CORRECT", func(t *testing.T) {
		// The new mfaAuthChallenge API correctly supports multiple devices
		// Create an in-memory U2F storage for authentication
		u2fStorage, err := u2flib.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err)

		// Get MFA challenges for all devices
		challenges, err := as.AuthServer.(*auth.Server).GetMFAAuthChallenge(ctx, user.GetName(), u2fStorage)
		require.NoError(t, err)

		// Verify that we got challenges for ALL 3 U2F devices
		require.NotNil(t, challenges, "Expected MFA challenges")
		require.Len(t, challenges.U2F, 3, "Expected 3 U2F challenges (one for each device)")

		// Verify each challenge is unique and corresponds to a device
		seenKeyHandles := make(map[string]bool)
		for i, challenge := range challenges.U2F {
			require.NotEmpty(t, challenge.KeyHandle, "Challenge %d has empty key handle", i)
			require.NotEmpty(t, challenge.Challenge, "Challenge %d has empty challenge", i)
			require.NotEmpty(t, challenge.AppID, "Challenge %d has empty AppID", i)

			// Check for uniqueness of key handles
			require.False(t, seenKeyHandles[challenge.KeyHandle],
				"Duplicate key handle in challenge %d", i)
			seenKeyHandles[challenge.KeyHandle] = true
		}

		// Verify we can authenticate with any of the devices
		for i, deviceName := range deviceNames {
			challenge := challenges.U2F[i]

			// Get the key handle as bytes to match against the device
			keyHandleBytes, err := base64.URLEncoding.WithPadding(base64.NoPadding).DecodeString(challenge.KeyHandle)
			require.NoError(t, err)

			mockDev := u2fDevices[deviceName]
			require.Equal(t, mockDev.KeyHandle, keyHandleBytes,
				"Key handle mismatch for device %s at challenge %d", deviceName, i)

			// Create a sign response using the mock device
			signResp, err := mockDev.SignResponse(&u2f.AuthenticateChallenge{
				Challenge: challenge.Challenge,
				AppID:     challenge.AppID,
				KeyHandle: challenge.KeyHandle,
			})
			require.NoError(t, err)

			// Verify the response can be validated
			authResp := u2f.AuthenticateChallengeResponse{
				KeyHandle:     signResp.KeyHandle,
				SignatureData: signResp.SignatureData,
				ClientData:    signResp.ClientData,
			}

			// This should succeed for any of the registered devices
			err = as.AuthServer.(*auth.Server).CheckU2FSignResponse(ctx, user.GetName(), &authResp)
			require.NoError(t, err, "Failed to verify sign response for device %s", deviceName)
		}
	})

	// TEST 3: Verify device management with multiple devices
	t.Run("DeviceManagement_MultipleDevices", func(t *testing.T) {
		// Test adding a new device when multiple already exist
		stream, err := cl.AddMFADevice(ctx)
		require.NoError(t, err)
		defer stream.CloseSend()

		// Initiate registration for a 4th device
		err = stream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_Init{
				Init: &proto.AddMFADeviceRequestInit{
					DeviceName: "u2f-device-4",
					Type:       proto.AddMFADeviceRequestInit_U2F,
				},
			},
		})
		require.NoError(t, err)

		// Should receive an existing MFA challenge (to authenticate before adding new device)
		resp, err := stream.Recv()
		require.NoError(t, err)

		existingChallenge := resp.GetExistingMFAChallenge()
		require.NotNil(t, existingChallenge, "Expected existing MFA challenge before adding new device")

		// With multiple devices, the challenge should include all 3 existing devices
		require.Len(t, existingChallenge.U2F, 3,
			"Expected challenges for all 3 existing U2F devices when adding a new device")

		// Respond with authentication using the first device
		device1Challenge := existingChallenge.U2F[0]
		device1 := u2fDevices[deviceNames[0]]

		signResp, err := device1.SignResponse(&u2f.AuthenticateChallenge{
			Challenge: device1Challenge.Challenge,
			AppID:     device1Challenge.AppID,
			KeyHandle: device1Challenge.KeyHandle,
		})
		require.NoError(t, err)

		err = stream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
				ExistingMFAResponse: &proto.MFAAuthenticateResponse{
					Response: &proto.MFAAuthenticateResponse_U2F{
						U2F: &proto.U2FResponse{
							KeyHandle:  signResp.KeyHandle,
							ClientData: signResp.ClientData,
							Signature:  signResp.SignatureData,
						},
					},
				},
			},
		})
		require.NoError(t, err)

		// Receive registration challenge for the new device
		resp, err = stream.Recv()
		require.NoError(t, err)

		regChallenge := resp.GetMFAChallenge().GetU2F()
		require.NotEmpty(t, regChallenge)

		// Register the new device
		device4, err := mocku2f.Create()
		require.NoError(t, err)

		regResp, err := device4.RegisterResponse(&u2f.RegisterChallenge{
			Challenge: regChallenge.Challenge,
			AppID:     regChallenge.AppID,
		})
		require.NoError(t, err)

		err = stream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_RegisterResponse{
				RegisterResponse: &proto.MFARegisterResponse{
					Response: &proto.MFARegisterResponse_U2F{
						U2F: &proto.U2FRegisterResponse{
							RegistrationData: regResp.RegistrationData,
							ClientData:       regResp.ClientData,
						},
					},
				},
			},
		})
		require.NoError(t, err)

		// Receive final confirmation
		resp, err = stream.Recv()
		require.NoError(t, err)
		require.NotNil(t, resp.GetDevice())

		// Verify all 4 devices are now registered
		devices, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
		require.NoError(t, err)
		require.Len(t, devices.Devices, 4, "Expected 4 U2F devices after adding 4th device")
	})

	// TEST 4: Verify challenge for deleting a device when multiple exist
	t.Run("DeleteDevice_WithMultipleDevices", func(t *testing.T) {
		// Create a stream to delete a device
		stream, err := cl.DeleteMFADevice(ctx)
		require.NoError(t, err)
		defer stream.CloseSend()

		// Initiate deletion of device 2
		err = stream.Send(&proto.DeleteMFADeviceRequest{
			Request: &proto.DeleteMFADeviceRequest_Init{
				Init: &proto.DeleteMFADeviceRequestInit{
					DeviceName: "u2f-device-2",
				},
			},
		})
		require.NoError(t, err)

		// Receive MFA challenge for authentication
		resp, err := stream.Recv()
		require.NoError(t, err)

		deleteChallenge := resp.GetMFAChallenge()
		require.NotNil(t, deleteChallenge)

		// The challenge should include challenges for ALL remaining devices
		// (at this point we should have 4 devices, so 4 U2F challenges)
		require.Len(t, deleteChallenge.U2F, 4,
			"Expected challenges for all 4 U2F devices when deleting a device")

		// Respond with authentication using the first device
		device1Challenge := deleteChallenge.U2F[0]
		device1 := u2fDevices[deviceNames[0]]

		signResp, err := device1.SignResponse(&u2f.AuthenticateChallenge{
			Challenge: device1Challenge.Challenge,
			AppID:     device1Challenge.AppID,
			KeyHandle: device1Challenge.KeyHandle,
		})
		require.NoError(t, err)

		err = stream.Send(&proto.DeleteMFADeviceRequest{
			Request: &proto.DeleteMFADeviceRequest_MFAResponse{
				MFAResponse: &proto.MFAAuthenticateResponse{
					Response: &proto.MFAAuthenticateResponse_U2F{
						U2F: &proto.U2FResponse{
							KeyHandle:  signResp.KeyHandle,
							ClientData: signResp.ClientData,
							Signature:  signResp.SignatureData,
						},
					},
				},
			},
		})
		require.NoError(t, err)

		// Receive acknowledgment
		resp, err = stream.Recv()
		require.NoError(t, err)
		require.NotNil(t, resp.GetAck())

		// Verify the device was deleted
		devices, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
		require.NoError(t, err)
		require.Len(t, devices.Devices, 3, "Expected 3 U2F devices after deleting one")

		// Verify that device 2 is gone
		for _, dev := range devices.Devices {
			require.NotEqual(t, "u2f-device-2", dev.Metadata.Name,
				"Device 'u2f-device-2' should have been deleted")
		}
	})

	// TEST 5: Verify client/server version compatibility
	t.Run("ClientServerCompatibility_U2FChallenges", func(t *testing.T) {
		// Test that the challenge format is compatible between old and new clients
		u2fStorage, err := u2flib.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err)

		challenges, err := as.AuthServer.(*auth.Server).GetMFAAuthChallenge(ctx, user.GetName(), u2fStorage)
		require.NoError(t, err)

		// The proto structure should support multiple U2F challenges
		require.Len(t, challenges.U2F, 3)

		// Each challenge should be properly formatted
		for _, challenge := range challenges.U2F {
			// Verify essential fields are present
			require.NotEmpty(t, challenge.KeyHandle)
			require.NotEmpty(t, challenge.Challenge)
			require.NotEmpty(t, challenge.AppID)

			// Verify key handle format (should be base64-encoded)
			keyBytes, err := base64.URLEncoding.WithPadding(base64.NoPadding).DecodeString(challenge.KeyHandle)
			require.NoError(t, err)
			require.NotEmpty(t, keyBytes)
		}
	})
}

// GetMFAAuthChallenge is a helper method that wraps the internal mfaAuthChallenge
// This is needed because mfaAuthChallenge is not exported.
// In the real server, this would be called through gRPC.
func (as *auth.TestAuthServer) GetMFAAuthChallenge(ctx context.Context, user string,
	u2fStorage u2f.AuthenticationStorage) (*proto.MFAAuthenticateChallenge, error) {
	// Use reflection or type assertion to access the private method
	// This is a workaround for testing
	authServer := as.AuthServer.(*auth.Server)
	return authServer.(*auth.Server).mfaAuthChallenge(ctx, user, u2fStorage)
}

